const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Set secure HTTP headers (CSP, X-Content-Type-Options, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate-limit all requests: max 100 requests per 15-minute window per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable the X-Powered-By header (leaks technology stack info)
app.disable('x-powered-by');

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameter "id" — must be a positive integer
    if (req.query.id !== undefined) {
      const id = Number(req.query.id);
      if (!Number.isInteger(id) || id <= 0) {
        return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // If a valid id was provided, filter to that user
    if (req.query.id !== undefined) {
      const user = users.find((u) => u.id === Number(req.query.id));
      if (!user) {
        return res.status(404).json({ error: 'User not found.' });
      }
      return res.json(user);
    }

    return res.json(users);
