const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---

// Set secure HTTP headers (XSS protection, content-type sniffing, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent DoS
app.use(express.json({ limit: '10kb' }));

// Global rate limiter: 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable the X-Powered-By header to avoid fingerprinting
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate and sanitize optional query parameters
  const allowedParams = ['name', 'id'];
  const unexpectedParams = Object.keys(req.query).filter(
    (key) => !allowedParams.includes(key)
  );

  if (unexpectedParams.length > 0) {
    return res.status(400).json({
      error: 'Invalid query parameters',
      invalid: unexpectedParams,
    });
  }

  // Example: validate `id` is a positive integer if provided
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({ error: '`id` must be a positive integer' });
    }
  }

  // Example: validate `name` is a safe alphanumeric string if provided
  if (req.query.name !== undefined) {
    if (typeof req.query.name !== 'string' || !/^[a-zA-Z0-9 _-]{1,100}$/.test(req.query.name)) {
      return res.status(400).json({
        error: '`name` must be 1-100 alphanumeric characters',
      });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Apply filters if provided
  let result = users;
  if (req.query.id) {
    result = result.filter((u) => u.id === Number(req.query.id));
  }
  if (req.query.name) {
    result = result.filter((u) =>
      u.name.toLowerCase().includes(req.query.name.toLowerCase())
    );
  }

  res.json(result);
});

// --- 404 handler for undefined routes ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
// Catches unhandled errors; never leaks stack traces to the client.
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err);
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error'
        : err.message,
  });
});

// --- Start server ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

